class Solution:

def evaluate_expression(self, expr: str) -> int:
    stack = []
    i = 0
    while i < len(expr):
        if expr[i].isdigit():
            stack.append(expr[i])
            i += 1
        elif expr[i] in '+-*/':
            operand1 = int(stack.pop())
            operand2 = int(stack.pop())
            if expr[i] == '+':
                stack.append(operand1 + operand2)
            elif expr[i] == '-':
                stack.append(operand1 - operand2)
            elif expr[i] == '*':
                stack.append(operand1 * operand2)
            elif expr[i] == '/':
                stack.append(operand1 / operand2)
            i += 1
        else:
            return 0
    return int(stack.pop())

