// Full executable C++ solution file
#include <iostream>
#include <stack>
#include <string>
int evaluateExpression(string expr) {
    std::stack<char> s;
    int i = 0;
    while (i < expr.length()) {
        if (isdigit(expr[i])) {
            s.push(expr[i]);
            i++;
        } else if (s.empty()) {
            s.push(expr[i]);
            i++;
        } else {
            if (expr[i] == '+') {
                int operand2 = s.top() - '0';
                s.pop();
                int operand1 = s.top() - '0';
                s.pop();
                s.push(operand1 + operand2);
            } else if (expr[i] == '-') {
                int operand2 = s.top() - '0';
                s.pop();
                int operand1 = s.top() - '0';
                s.pop();
                s.push(operand1 - operand2);
            } else if (expr[i] == '*') {
                int operand2 = s.top() - '0';
                s.pop();
                int operand1 = s.top() - '0';
                s.pop();
                s.push(operand1 * operand2);
            } else if (expr[i] == '/') {
                int operand2 = s.top() - '0';
                s.pop();
                int operand1 = s.top() - '0';
                s.pop();
                s.push(operand1 / operand2);
            }
            i++;
        }
    }
    return (int)s.top() - '0';
}
int main() {
    string expr;
    cin >> expr;
    cout << evaluateExpression(expr) << endl;
    return 0;
}
